require_once __DIR__ . '/../includes/media_delivery.php';
require_once __DIR__ . '/../includes/revenue_access_governance.php';
sf_revenue_guard_json_write('video_tracking',240,900);$data=sf_request_json();$videoId=sf_int_from_request($data,'video_id');$eventType=strtolower(trim((string)($data['event_type']??'play')));$allowed=['play','pause','seek','progress','complete','rewatch','error'];if(!in_array($eventType,$allowed,true))$eventType='play';if($videoId<=0)sf_json_response(['ok'=>false,'error'=>'video_id_required'],422);$record=sf_media_video_record($videoId);if(!$record)sf_json_response(['ok'=>false,'error'=>'video_not_found'],404);$full=sf_media_user_can_access('video',$record,'stream');$preview=sf_media_user_can_access('video',$record,'preview');if(!$full&&!$preview)sf_json_response(['ok'=>false,'error'=>'access_denied'],403);$episodeId=(int)($record['episode_id']??0);$requestEpisode=sf_int_from_request($data,'episode_id');if($episodeId<=0)$episodeId=$requestEpisode;if($requestEpisode>0&&$episodeId>0&&$requestEpisode!==$episodeId)sf_json_response(['ok'=>false,'error'=>'episode_video_mismatch'],422);$metrics=sf_revenue_tracking_metrics('video',$videoId,$record,$eventType,max(0,sf_int_from_request($data,'position_seconds')),max(0,sf_int_from_request($data,'seconds_watched')),max(0,min(100,sf_float_from_request($data,'percent_complete'))),$full);$source=substr((string)($data['source_page']??($_SERVER['HTTP_REFERER']??'')),0,120);$userId=sf_current_user_id();$session=sf_session_key();$pdo=sf_db();if(!$pdo)sf_json_response(['ok'=>true,'stored'=>false,'mode'=>'no_database_configured']);$member=$userId?sf_entitlement_snapshot($userId):[];$canTrack=$episodeId<=0||!empty($member['can_track_episodes'])||(($record['access_level']??'')==='public');
try{$pdo->beginTransaction();$stmt=$pdo->prepare('INSERT INTO video_watch_events (user_id,video_id,episode_id,session_key,event_type,position_seconds,seconds_watched,percent_complete,source_page,ip_hash,user_agent_hash) VALUES (?,?,?,?,?,?,?,?,?,?,?)');$stmt->execute([$userId,$videoId,$episodeId?:null,$session,$metrics['event_type'],$metrics['position_seconds'],$metrics['seconds_delta'],$metrics['percent_complete'],$source,sf_client_hash($_SERVER['REMOTE_ADDR']??null),sf_client_hash($_SERVER['HTTP_USER_AGENT']??null)]);if($userId&&!empty($metrics['eligible_for_member_progress'])){$progress=$pdo->prepare("INSERT INTO user_video_progress (user_id,video_id,last_position_seconds,total_seconds_watched,watch_count,completed_count,last_event_type,last_watched_at) VALUES (?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE last_position_seconds=VALUES(last_position_seconds),total_seconds_watched=total_seconds_watched+VALUES(total_seconds_watched),watch_count=watch_count+VALUES(watch_count),completed_count=completed_count+VALUES(completed_count),last_event_type=VALUES(last_event_type),last_watched_at=NOW()");$progress->execute([$userId,$videoId,$metrics['position_seconds'],$metrics['seconds_delta'],$metrics['event_type']==='play'?1:0,$metrics['event_type']==='complete'?1:0,$metrics['event_type']]);if($episodeId>0&&$canTrack){$completed=$metrics['event_type']==='complete';$episode=$pdo->prepare("INSERT INTO user_episode_progress (user_id,episode_id,primary_video_id,last_position_seconds,total_seconds_watched,completed,completed_at,last_watched_at) VALUES (?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE primary_video_id=VALUES(primary_video_id),last_position_seconds=VALUES(last_position_seconds),total_seconds_watched=total_seconds_watched+VALUES(total_seconds_watched),completed=GREATEST(completed,VALUES(completed)),completed_at=COALESCE(VALUES(completed_at),completed_at),last_watched_at=NOW()");$episode->execute([$userId,$episodeId,$videoId,$metrics['position_seconds'],$metrics['seconds_delta'],$completed?1:0,$completed?date('Y-m-d H:i:s'):null]);}$item=sf_library_catalog_item('video',$videoId,$metrics['event_type']==='complete'?'completed':'watchlist',['progress_percent'=>(int)round($metrics['percent_complete']),'position_seconds'=>$metrics['position_seconds'],'metadata'=>['episode_id'=>$episodeId,'last_event_type'=>$metrics['event_type']]]);if($item)sf_library_save_item((int)$userId,$item);}$pdo->commit();sf_json_response(['ok'=>true,'stored'=>true,'verified'=>true,'full_access'=>$full,'metrics'=>$metrics]);}catch(Throwable$e){if($pdo->inTransaction())$pdo->rollBack();error_log('Video tracking failed: '.$e->getMessage());sf_json_response(['ok'=>false,'error'=>'tracking_failed'],500);}
